record.field:
{
    "type": "object",
    "properties": {
        "subject":         {"type": "string",  "description": "Short title describing the issue"},
        "description":     {"type": "string",  "description": "Full description of the error or issue"},
        "channel_id":      {"type": "integer", "description": "Discuss channel ID where the issue was reported (optional)"},
        "assignee_id":     {"type": "integer", "description": "res.users ID to assign the ticket to (optional)"},
        "partner_id":      {"type": "integer", "description": "Customer res.partner ID if already known (optional)"},
        "customer_name":   {"type": "string",  "description": "Customer full name — used to find or store on the ticket (optional)"},
        "customer_email":  {"type": "string",  "description": "Customer email address (optional)"},
        "customer_phone":  {"type": "string",  "description": "Customer phone number (optional)"},
        "tag_names":       {"type": "array",   "description": "Tag names to apply, e.g. ['bug', 'urgent']. Tags are created if they do not exist.", "items": {"type": "string"}}
    },
    "required": ["subject", "description"]
}

{
    "type": "object",
    "properties": {
        "email":       {"type": "string",  "description": "Email to search — preferred, case-insensitive. Omit if unknown."},
        "name":        {"type": "string",  "description": "Name to search when no email is given. Required for creating a new contact."},
        "phone":       {"type": "string",  "description": "Phone number — only stored when creating a new contact. Omit if unknown."},
        "search_only": {"type": "boolean", "description": "Pass true to only search and never create a new contact."}
    },
    "required": []
}

_email = (email or '').strip()
_name = (name or '').strip()
_phone = (phone or '').strip()
_only = bool(search_only)

if _email:
    partners = env['res.partner'].sudo().search([('email', '=ilike', _email)], limit=5)
elif _name:
    partners = env['res.partner'].sudo().search([('name', 'ilike', _name)], limit=5)
else:
    ai['result'] = 'Error: provide at least an email or a name to search.'
    partners = env['res.partner'].sudo()

if partners:
    lines = ['Found %d contact(s):' % len(partners)]
    for p in partners:
        lines.append('  ID %d | %s | email: %s | phone: %s' % (
            p.id, p.name, p.email or '-', p.phone or '-'))
    ai['result'] = '\n'.join(lines)
elif not (_email or _name):
    pass  # error already set above
elif _only:
    ai['result'] = 'No contact found matching the search.'
elif not _name:
    ai['result'] = 'Error: a name is required to create a new contact.'
else:
    vals = {'name': _name}
    if _email:
        vals['email'] = _email
    if _phone:
        vals['phone'] = _phone
    p = env['res.partner'].sudo().create(vals)
    ai['result'] = 'New contact created — ID %d | %s | email: %s | phone: %s' % (
        p.id, p.name, p.email or '-', p.phone or '-')

{
    "type": "object",
    "properties": {
        "query": {"type": "string",  "description": "Keyword to look for in article titles and body. Omit to list all accessible articles."},
        "limit": {"type": "integer", "description": "Maximum number of results to return (default 5, max 20)"}
    },
    "required": []
}

{
    "type": "object",
    "properties": {
        "lead_name":   {"type": "string",  "description": "Lead title, e.g. 'Interest in Product X — Acme Corp'"},
        "email":       {"type": "string",  "description": "Customer email (optional)"},
        "phone":       {"type": "string",  "description": "Customer phone (optional)"},
        "description": {"type": "string",  "description": "Notes or context about the lead (optional)"},
        "partner_id":  {"type": "integer", "description": "ID of an existing contact to link (optional)"}
    },
    "required": ["lead_name"]
}

base_url = env['ir.config_parameter'].sudo().get_param('web.base.url')

vals = {'name': lead_name}
if email:
    vals['email_from'] = email.strip()
if phone:
    vals['phone'] = phone.strip()
if description:
    vals['description'] = description.strip()
if partner_id:
    vals['partner_id'] = int(partner_id)

lead = env['crm.lead'].sudo().create(vals)
ai['result'] = "Lead '%s' created (ID %d). Link: %s/odoo/crm/%d" % (
    lead.name, lead.id, base_url, lead.id)
